var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"큭!","JPN":"くっ！","ENG":"Kgh!","TWN":"呃！"},"stage":{"bg":"THRONE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROSARIA_FALLEN_NAME_CHANGE","text":{"KOREA":"실망스럽구나, 늑대.","JPN":"残念じゃのう、オオカミ。","ENG":"How disappointing, Wolf.","TWN":"真令人失望啊，狼。"},"stage":{"bg":"THRONE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROSARIA_FALLEN_NAME_CHANGE","text":{"KOREA":"고작 여기까지 오는데 기운을 다 빼기라도 한 건가?","JPN":"ここまで来るのに力を使い切ってしまったのか？","ENG":"Did you use up all your energy while getting here?","TWN":"難道只是來到這裡就已經耗盡了所有力氣嗎？"},"stage":{"bg":"THRONE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"헉… 헉…","JPN":"はあ……はあ……","ENG":"*Huff* *Huff*","TWN":"呼……呼……"},"stage":{"bg":"THRONE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"방심하긴…","JPN":"油断するには……","ENG":"Don't let your guard down...","TWN":"勸你……"},"stage":{"bg":"THRONE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"아직 일러!","JPN":"まだ早い！","ENG":"just yet!","TWN":"別太輕敵！"},"stage":{"bg":"THRONE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROSARIA_FALLEN_NAME_CHANGE","text":{"KOREA":"…음?","JPN":"……む？","ENG":"...Mm?","TWN":"……嗯？?"},"stage":{"bg":"THRONE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"닿았나?!","JPN":"届いたか！？","ENG":"Did I get her?!","TWN":"打中了嗎？！"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOLF_NPC_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"그럴 리가.","JPN":"まさか。","ENG":"Of course, not.","TWN":"怎麼可能。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOLF_NPC_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"뭣…","JPN":"なっ……","ENG":"What...?","TWN":"什、什麼……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOLF_NPC_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"커헉!","JPN":"がはっ！","ENG":"Kuh!","TWN":"咳！"},"stage":{"bg":"THRONE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROSARIA_FALLEN_NAME_CHANGE","text":{"KOREA":"대적자가 아니면서도 신위에 범접할 수 있는 검이라.","JPN":"敵対者でもなかろうに、神威に近づける剣とは。","ENG":"A sword that gives you access to divine power, even when you're not the Antagonist.","TWN":"即使不是敵對者，這把劍也能觸及到神威啊。"},"stage":{"bg":"THRONE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROSARIA_FALLEN_NAME_CHANGE","text":{"KOREA":"썩 나쁘지 않은 이빨을 가졌구나.","JPN":"なかなか悪くない牙を持っているのじゃな。","ENG":"Your fangs are not that bad, it seems.","TWN":"至少牙齒還不錯嘛。"},"stage":{"bg":"THRONE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROSARIA_FALLEN_NAME_CHANGE","text":{"KOREA":"하지만 아무리 날카로운 이빨도 닿지 못하면 쓸모가 없지.","JPN":"だが、いくら鋭い牙でも届かないなら無用であろう。","ENG":"Yet, even the sharpest fangs cannot pierce what it cannot reach.","TWN":"但是再鋒利的牙齒，咬不到人就沒有用了。"},"stage":{"bg":"THRONE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"큭… 몸이 안 움직여…?","JPN":"くっ……体が動かない……？","ENG":"Kgh... Why won't my body move...?","TWN":"呃……身體動不了了……？"},"stage":{"bg":"THRONE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"ROSARIA_FALLEN_NAME_CHANGE","text":{"KOREA":"…끝이다.","JPN":"……終わりじゃ。","ENG":"...This is your end.","TWN":"……結束了。"},"stage":{"bg":"THRONE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"THRONE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"C":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROSARIA_FALLEN_NAME_CHANGE","text":{"KOREA":"역시, 너였구나. 힐데.","JPN":"やはり其方か。ヒルデ。","ENG":"As expected. So it was you, Hilde.","TWN":"果然是你，希爾德。"},"stage":{"bg":"THRONE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"ROSARIA_FALLEN_NAME_CHANGE","text":{"KOREA":"북부전선에서 날 가로막았던 그 힘도… 바로 너였을 테지.","JPN":"北部戦線で妾を阻んだその力も……其方だったのじゃろう。","ENG":"The power that blocked me on the northern front... was you.","TWN":"在北部戰線阻擋我的那股力量……一定就是你吧。"},"stage":{"bg":"THRONE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"날 찾고 있었나?","JPN":"私を探していたのか？","ENG":"Were you looking for me?","TWN":"你在找我嗎？"},"stage":{"bg":"THRONE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ROSARIA_FALLEN_NAME_CHANGE","text":{"KOREA":"그래. 클리포트 게임을 시작하면 날 죽일 수 있을 테니 반드시 나타날 거라 생각했어.","JPN":"然様。クリフォトゲームを始めれば妾を殺せるからの。必ず現われると思っていたのじゃ。","ENG":"Yes. I thought you'd show up, since starting the Qliphoth Game would enable you to kill me.","TWN":"沒錯。逆卡巴拉遊戲就是你們殺死我的機會，所以我想你一定會出現的。"},"stage":{"bg":"THRONE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"ROSARIA_FALLEN_NAME_CHANGE","text":{"KOREA":"여러 세계를 들쑤시다보면 너 같은 녀석을 만나게 될 거라고, 탐미엘이 그러더군.","JPN":"色んな世界をひっかき回せば其方のようなやつに会うだろうと、タミエルが言っていた。","ENG":"Tammiel said that I'd meet someone like you if I were to tamper with enough worlds.","TWN":"塔米爾說過，只要繼續征服更多的世界，總有一天就會再遇到你。"},"stage":{"bg":"THRONE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"네가… 탐미엘을 만난 적이 있다고?","JPN":"お前が……タミエルに会ったことがあるのか？","ENG":"You've... met Tammiel before?","TWN":"你……見過塔米爾嗎？"},"stage":{"bg":"THRONE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ROSARIA_FALLEN_NAME_CHANGE","text":{"KOREA":"어차피 한 쪽은 사라질 텐데, 더 긴 이야기는 필요 없겠지.","JPN":"どうせ片方は消えるのじゃ。これ以上長い話は必要あるまい。","ENG":"One of us will perish today, so there seems no need to talk any further.","TWN":"反正我們之間總有一方會消失，沒必要再多說了吧。"},"stage":{"bg":"THRONE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"ROSARIA_FALLEN_NAME_CHANGE","text":{"KOREA":"자, 시작하자. 우리 둘만의 전투를.","JPN":"さあ、始めるとしよう。妾と其方、2人だけの戦闘を。","ENG":"Now, let us begin. A battle just for the two of us.","TWN":"好了，讓我好好享受吧。這場只有我們兩個人的戰鬥。"},"stage":{"bg":"THRONE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"THRONE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"기대처럼 즐거운 시간은 아닐 거다.","JPN":"期待どおりの楽しい時間ではないはずだ。","ENG":"This won't be as enjoyable as you anticipated.","TWN":"不會如你所願的。"},"stage":{"bg":"THRONE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_SERIOUS"},"R":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"금방 끝날 테니…!","JPN":"すぐ終わるだろうからな……！","ENG":"For it'll soon be over...!","TWN":"因為……很快就會結束！"},"stage":{"bg":"THRONE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"발퀴레 근접 반응형 집속검","JPN":"ワルキューレ近接反応型集束剣","ENG":"Valkyrie melee response focus blade.","TWN":"女武神近戰反應型集束劍"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROSARIA_FALLEN_NAME_CHANGE","text":{"KOREA":"아하핫! 그래, 이 감각! 이걸 원했어!","JPN":"あははっ！　ああ、この感覚！　これが欲しかったのじゃ！","ENG":"Ah hah hah! Yes, this feeling! This is what I've been waiting for!","TWN":"哈哈哈！對，就是這種感覺！這就是我想要的！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROSARIA_FALLEN_NAME_CHANGE","text":{"KOREA":"처음부터 도망치지 않고 이렇게 싸웠다면, 세계를 멸망시키는 수고 따위도 할 필요 없었을 텐데 말이야.","JPN":"最初から逃げずにこうやって戦っていたのなら、世界を滅亡させる苦労などせずに済んだのじゃがな。","ENG":"If you had just fought me in the beginning instead of fleeing, I wouldn't have had to go through the trouble of destroying worlds.","TWN":"如果你一開始沒有逃跑，而是這樣戰鬥的話，就不需要我費心去毀滅世界了。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"전투가 길어져선 안돼…","JPN":"戦闘が長引くのは駄目だ……","ENG":"I must not let this battle drag on...","TWN":"絕對不能拖延……"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"다음 일격으로 끝내야 한다.","JPN":"次の一撃で終わらせなければ。","ENG":"I'll have to finish her with this next strike.","TWN":"下一擊必須結束戰鬥。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"하아아앗!!","JPN":"はあああっ！！","ENG":"HAAAAA!!!!","TWN":"哈啊啊啊！！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"새로운 신성 타입 에너지를 감지.","JPN":"新しい神聖タイプのエネルギーを感知。","ENG":"New Divinity energy type detected.","TWN":"檢測到新的神聖類型能量。"},"stage":{"bg":"MAINSTREAM_000002","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L15_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"CSE 수치가 비약적으로 상승 중…","JPN":"CSE数値が飛躍的に上昇中……","ENG":"CSE rapidly increasing...","TWN":"CSE數值正在急劇上升……"},"stage":{"bg":"MAINSTREAM_000002","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"차원계면이 곧 붕괴됩니다. 대피하십시오.","JPN":"まもなく次元界面が崩壊します。退避してください。","ENG":"The dimension surface will soon collapse. Please evacuate.","TWN":"次元介面即將崩潰。請撤離。"},"stage":{"bg":"MAINSTREAM_000002","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…결국 이렇게 되고 말았군.","JPN":"……結局こうなってしまったか。","ENG":"...So it has come to this..","TWN":"……最後還是變成這樣了啊。"},"stage":{"bg":"MAINSTREAM_000002","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"모든 준비를 마쳤다고 생각했지만… 결국 부족했던 건가.","JPN":"すべての準備が整ったと思ったんだが……結局足りなかったのか。","ENG":"I thought I had made all the necessary preparations, but... it was not enough in the end.","TWN":"我以為一切都準備好了……結果還是不夠嗎？"},"stage":{"bg":"MAINSTREAM_000002","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"차원계면이 곧 붕괴됩니다. 신속히 현실로 부상하십시오.","JPN":"まもなく次元界面が崩壊します。直ちに現実へと浮上してください。","ENG":"The dimension surface will soon collapse. Swiftly emerge back to the Normalside.","TWN":"次元介面即將崩潰。請立即返回現世。"},"stage":{"bg":"MAINSTREAM_000002","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"대피하십시오… 오십니다…","JPN":"退避してください……お見えになります……","ENG":"Evacuate... She's coming...","TWN":"……請……撤離……"},"stage":{"bg":"MAINSTREAM_000002","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SYS_RUNNING"},{"id":"L22_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"오십니다… 그 분이…","JPN":"お見えになります……あの方が……","ENG":"She is... coming...","TWN":"她……來了……"},"stage":{"bg":"MAINSTREAM_000002","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"뭐야?","JPN":"何だ？","ENG":"Huh?","TWN":"怎麼回事？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"왜…","JPN":"どうして……","ENG":"Why...","TWN":"為什麼……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"아무것도 움직이지 않지…?","JPN":"何も動かない……？","ENG":"is everything still...?","TWN":"一切都靜止了……？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"네가 <color=#ffd34c>우리의 힘</color>을 사용해 날 깨웠기 때문이야.","JPN":"あなたが<color=#ffd34c>私たちの力</color>を使って私を目覚めさせたから。","ENG":"It is because you have used <color=#ffd34c>our power</color> to awaken me.","TWN":"因為你使用<color=#ffd34c>我們的力量</color>喚醒了我。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"너도 알고 있겠지. 클리포트 게임에서 그 힘을 쓰면 안된다는 걸.","JPN":"あなたも知っているでしょ？　クリフォトゲームでその力を使ってはいけないということ。","ENG":"You knew not to use that power in the Qliphoth Game.","TWN":"你也知道的吧。在逆卡巴拉遊戲裡不能使用那種力量。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"탐미엘…?","JPN":"タミエル……？","ENG":"Tammiel...?","TWN":"塔米爾……？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":"하지만 넌 늑대를 지키기 위해 그 힘을 쓸 수밖에 없어. 그게 운명이란 거야.","JPN":"だけど、あなたはオオカミを守るためにその力を使うしかない。それが運命ってことだよ。","ENG":"However, you have no choice but to use it to protect the Wolf. That is what we call fate.","TWN":"但是你只能用它來保護狼。這就是命運。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":"몇 번을 반복해도, 결과는 같을 테고.","JPN":"何度繰り返しても、結果は同じ。","ENG":"No matter how many times it is repeated, the outcome will be the same.","TWN":"無論重複多少次，結果都是一樣的。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":"이번에도 늑대를 열심히 길러냈구나.","JPN":"今回も熱心にオオカミを育てたんだね。","ENG":"It seems you've raised the Wolf well this time as well.","TWN":"這次也努力培養了狼嗎？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":"아스모데우스와 합을 겨룰 정도라니… 나쁘지 않은 성장이네.","JPN":"アスモデウスと力を競い合うなんて……悪くない成長だよ。","ENG":"Being strong enough to fight on par with Asmodeus... Her growth is not that bad.","TWN":"竟然能與阿斯蒙蒂斯抗衡……成長得不錯嘛。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"안돼… 손대지 마…!","JPN":"駄目だ……手を出すな……！","ENG":"No... STOP...!","TWN":"不要……別碰她……！"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":"게임의 규칙대로, 전부 거둬가는 것뿐이야.","JPN":"ゲームのルールに従って、すべてを取り込んでいくだけだよ。","ENG":"I am merely taking everything away, as the rules of the game dictate.","TWN":"按照遊戲的規則，全都收走而已。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":"그럼 다음 늑대도 잘 부탁해.","JPN":"じゃあ、次のオオカミもよろしく。","ENG":"Then, I'll see you again when the next Wolf is ready.","TWN":"那下一個狼也拜託了。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":"나의 힐데.","JPN":"私のヒルデ。","ENG":"My Hilde.","TWN":"我的希爾德。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"그만 둬!","JPN":"やめろ！","ENG":"STOP IT!","TWN":"不准走。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"탐미엘!!!!!!!!!!!!!!","JPN":"タミエル！！！！！！！！！","ENG":"TAMMIEL!!!!!!!!!!!","TWN":"塔米爾！！！！！！！！！！！！"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"아픈 과거를 가진 히로인이 악몽에서 깨어나며 시작하는 이야기라… 전형적인 클리셰로군.","JPN":"辛い過去を持つヒロインが悪夢から覚めることによって始まる物語か……典型的なクリシェだよ。","ENG":"A story in which a heroine with a painful past awakens from a nightmare... Typical cliche.","TWN":"擁有著痛苦過去的女英雄從惡夢中醒來……還真是老套的情節呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L3_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"너처럼 우악스런 여장부가 히로인 역할에 어울리는진 모르겠지만 말이야.","JPN":"あなたのような荒々しい女傑がヒロインとしてふさわしいのかはよくわからないけど。","ENG":"I'm not so sure if a brute female protagonist like you would be suitable for the heroine role, though.","TWN":"不過像你這種粗魯野蠻的性格，是否能扮演好女主角還真不好說……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"내가… 잠들었던가?","JPN":"私は……眠っていたのか？","ENG":"Did I... fall asleep?","TWN":"我……睡著了嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"피곤할 만도 하지. 북방 놈들의 감시를 피하기 위해 일주일을 꼬박 걸었으니까.","JPN":"疲れるはずだよ。北方のやつらの監視を避けるために1週間ずっと歩きつづけたんだから。","ENG":"I'm sure you're exhausted. You walked for a week straight to avoid getting caught by those Northern Union jerks.","TWN":"你肯定是累到了。為了避開北方和議會的監視，我們整整走了一個星期呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그래도 그런 악몽을 꿀 땐 조심해라.","JPN":"でも、そんな悪夢を見る時には気をつけて。","ENG":"But still, be careful when you have nightmares like that.","TWN":"但是，做那種惡夢還是要小心點……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그 녀석 이름을 함부로 크게 불렀다가 진짜 나타나기라도 하면 난 감당 못한다고.","JPN":"あいつの名前をうっかり大声で叫んで本当に現われでもしたら、私は手に負えないからね。","ENG":"I won't be able to help you if she really appears in front of you for shouting her name.","TWN":"你要是真把那傢伙給叫出來了，我可應付不了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"과거를 본 것 같은데… 무슨 상황이었는지 기억이 나질 않는군.","JPN":"過去の夢を見たようだが……どんな状況だったか思い出せない。","ENG":"I feel like I saw my past, but... I can't remember what it was about.","TWN":"我好像看到了過去……但不記得是什麼情況了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"침식지대의 영향이겠지. 네 기억이 보관된 곳과 그리 멀지 않은 곳이니까.","JPN":"侵食地帯の影響でしょ。あなたの記憶が保管されているところからそんなに離れていないところなんだから。","ENG":"It's the effect of the Corrupted Area. You see, it's not far from where your memories are stored.","TWN":"那大概是侵蝕地帶的影響吧。這裡離你存放記憶的地方不遠了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"앞으로 반나절이면 도착할 거야.","JPN":"あと半日もあれば到着するよ。","ENG":"We'll arrive in half a day.","TWN":"最多再過半天……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"북방합의체가 외부의 접근을 삼엄하게 막고 있을 테지만, 이 몸이 뚫어줄 테니 걱정 말라구.","JPN":"北方合意体が外部の接近を厳重に塞いでいるだろうけど、この私が通れるようにしてあげるから心配しないで。","ENG":"The Northern Union has tight security against access from the outside, but I'll get you in. Trust me.","TWN":"雖然北方和議會會嚴防死守，但我會幫你過去的，相信我吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"관리국의 관리도 거부하는 녀석들이 뭣하러 균열을 지키고 있지?","JPN":"管理局の管理も拒否しているやつらが、何のために亀裂を守っているんだ？","ENG":"Those bastards refused the management of the Administration. What are they doing guarding a Crevice?","TWN":"那些拒絕管理的傢伙為什麼也要守著峽谷？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"표면적으론 국민의 안전을 위해서라고 둘러대지만… 보나마나 연구가 목적일 거야.","JPN":"表向きは国民の安全のためだって言ってるけど……考えるまでもなく目的は研究でしょうね。","ENG":"They are saying it's for the safety of their people, but... I'm pretty sure it's for research purposes.","TWN":"表面上說是為了國民的安全……但我猜他們肯定是為了研究。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그림자마저 실험도구로 삼는 녀석들에게, 그라운드 제로의 균열은 금단의 과실로 가득 찬 동산이나 마찬가지니까.","JPN":"シャドウさえ実験の道具にするようなやつらには、グラウンド・ゼロの亀裂は大量に禁断の果実がなる園も同然なんだから。","ENG":"These people even use Shadows as test subjects. So, Ground Zero's Crevice is like a paradise full of forbidden fruit to them.","TWN":"那些傢伙連暗影都敢拿來當實驗品，G0的峽谷對他們來說就像是充滿禁果的樂園。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너, 아까부터 뭘 그렇게 먹고 있는 거냐?","JPN":"お前、さっきから何を食べている？","ENG":"Hey, what are you even eating?","TWN":"……你從剛才開始一直在吃什麼？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"응? 네가 준 이터니움.","JPN":"うん？　あなたがくれたエタニウム。","ENG":"Hmm? It's the Eternium you gave me.","TWN":"什麼？是你給的永恆之金呀。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"필요하다고 해서 기껏 구했더니, 그걸 먹는다고?","JPN":"必要だと言うからせっかく譲ったのに、それを食べるのか？","ENG":"I got them because you said you needed them, and you're eating them now?","TWN":"好不容易才弄到了你要的東西，居然是要吃掉？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"누군 맛있어서 먹는 줄 알아? 네 기억을 보관한 과거까지 가려면 이걸로 힘을 보충해둬야 하거든?","JPN":"美味しいから食べてると思ってるの？　あなたの記憶を保管している過去まで行くためには、これで力を補充しないといけないのよ。","ENG":"You think I'm eating it because I want to? I need to consume it to replenish my strength to get where your memories are stored.","TWN":"你以為這是因為好吃才吃的嗎！？為了回到保存你記憶的地方，必須用這個補充能量好嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"네가 말한 대로 과거에 가면, 내 힘을 전부 되찾을 수 있는 건가?","JPN":"お前の言うとおり過去に行けば、私の力をすべて取り戻せるのか？","ENG":"If I do go back to the past like you said, will I be getting all of my powers back?","TWN":"那麼如果按照你說的拿回過去，我能找回全部的力量嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"네 힘 뿐만이 아니야.","JPN":"あなたの力だけじゃない。","ENG":"It won't just be your powers.","TWN":"不僅僅是你的力量。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"널 힘들게 했던 기억도 전부 함께 돌아올 테니까.","JPN":"あなたを苦しませた記憶も全部一緒に戻ってくるよ。","ENG":"All the bad memories will come flooding in too.","TWN":"那些讓你痛苦的記憶也會一同回來。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"상관없다.","JPN":"構わん。","ENG":"That doesn't concern me.","TWN":"無所謂。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"내 사명을 지키려면, 힘이 반드시 필요하니까.","JPN":"私の使命を果たすためには、必ず力が必要だからな。","ENG":"I require my powers to fulfill my duty.","TWN":"為了守護我的使命，力量是必不可少的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"참… 예나 지금이나 저런 점은 한결 같네.","JPN":"まったく……昔も今もそういうところは変わらないね。","ENG":"Ugh... You haven't changed, have you?","TWN":"唉……不管是過去還是現在，這一點還真是從來都沒有變。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그래서 알기 쉽단 말이지.","JPN":"だからわかりやすいんだけど。","ENG":"That's why you're so easy to read.","TWN":"所以才說你很容易讀懂。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};